def opts(ans, spread=5, minv=0):
    s={ans}
    for d in [1,-1,2,-2,3,-3,5,-5,10,-10,4,-4,20,-20]:
        v=ans+d
        if v>=minv and v!=ans: s.add(v)
        if len(s)>=4: break
    arr=list(s)
    random.shuffle(arr)
    return arr[:4]

