    return "  {\n"+f"    id: 'k_basic_{i:03}',\n    kanji: '{kanji}',\n    reading: '{reading}',\n    contextBefore: '{esc(before)}',\n    contextAfter: '{esc(after)}',\n    hint: '{esc(hint)}',\n    strokeCount: {st},\n  }}"
